// Extract request data and merge with config
const input = $input.first().json;
const config = input.config;
const data = input.request?.body || input.request || {};

const question = data.question || data.chatInput || '';
const familyId = data.family_id;
const sessionId = data.session_id || `session-${Date.now()}`;
const chatHistory = data.chat_history || [];

if (!question) {
  throw new Error('No question provided');
}

if (!familyId) {
  throw new Error('No family_id provided - please select a family first');
}

return [{
  json: {
    config: config,
    question: question,
    family_id: familyId,
    session_id: sessionId,
    chat_history: chatHistory
  }
}];

// Generate sparse vector for BM25
function hashCode(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) - hash) + str.charCodeAt(i);
    hash = hash & hash;
  }
  return Math.abs(hash);
}

const inputData = $('Extract Input').first().json;
const embedding = $input.first().json.embedding;

const words = inputData.question.toLowerCase().split(/\W+/).filter(w => w.length > 2);
const wordCounts = {};
words.forEach(w => { wordCounts[w] = (wordCounts[w] || 0) + 1; });

const indices = [], values = [];
Object.entries(wordCounts).forEach(([word, count]) => {
  indices.push(hashCode(word) % 30000);
  values.push(count);
});

return [{ json: {
  config: inputData.config,
  question: inputData.question,
  family_id: inputData.family_id,
  session_id: inputData.session_id,
  chat_history: inputData.chat_history || [],
  dense_vector: embedding,
  sparse_vector: { indices, values }
}}];

const prevData = $('Prepare Vectors').first().json;
const searchResponse = $input.first().json;
const results = searchResponse.result?.points || [];

return [{ json: {
  config: prevData.config,
  question: prevData.question,
  family_id: prevData.family_id,
  session_id: prevData.session_id,
  chat_history: prevData.chat_history || [],
  result: results,
  result_count: results.length
}}];

const familyId = $input.first().json.family_id;
const familyName = familyId.charAt(0).toUpperCase() + familyId.slice(1);
return [{ json: {
  output: `I couldn't find any relevant documents for your question in the ${familyName} family files. Please make sure documents have been indexed for this family, or try rephrasing your question.`
}}];

// Keyword boosting to get top candidates for reranking
const inputData = $input.first().json;
const question = inputData.question.toLowerCase();
const familyId = inputData.family_id;
const results = inputData.result || [];

const questionWords = question.split(/\W+/).filter(w => w.length > 3);

const scored = results.map(result => {
  const text = (result.payload.text || '').toLowerCase();
  const contextText = (result.payload.context_text || '').toLowerCase();
  const docTitle = (result.payload.document_title || '').toLowerCase();

  let keywordScore = 0;
  for (const word of questionWords) {
    if (text.includes(word)) keywordScore += 0.2;
    if (contextText.includes(word)) keywordScore += 0.1;
    if (docTitle.includes(word)) keywordScore += 0.1;
  }
  keywordScore += result.score * 0.1;

  return {
    id: result.id,
    rrf_score: result.score,
    keyword_score: keywordScore,
    title: result.payload.document_title || 'Unknown',
    text: result.payload.text || '',
    context_text: result.payload.context_text || '',
    page_num: result.payload.page_num || 1,
    payload: result.payload
  };
});

const candidates = scored
  .sort((a, b) => b.keyword_score - a.keyword_score)
  .slice(0, 10);

return [{ json: {
  config: inputData.config,
  question: inputData.question,
  family_id: familyId,
  chat_history: inputData.chat_history || [],
  candidates: candidates
}}];

// Pointwise 0-10 Reranker with Parallel Processing
// Uses a chat model to score document relevance on a 0-10 scale

const inputData = $input.first().json;
const { config, question, candidates, family_id, chat_history } = inputData;

if (!candidates || candidates.length === 0) {
  return [{ json: { config, question, family_id, chat_history: chat_history || [], top_results: [] }}];
}

// Get config values
const MODEL_NAME = config.RERANKER_MODEL;
const OLLAMA_URL = config.OLLAMA_URL;
const TOP_K = config.RERANKER_TOP_K || 5;

// Bind HTTP helper for use in async operations
const httpRequest = this.helpers.httpRequest.bind(this.helpers);

// Parallel scoring - all candidates scored concurrently
const scorePromises = candidates.map(async (doc) => {
  // Truncate text to ~800 chars to speed up LLM processing
  const textPreview = (doc.text || '').substring(0, 800).replace(/\n/g, ' ');

  // Pointwise scoring prompt - asks for 0-10 score instead of Yes/No
  const prompt = `Task: Rate the relevance of the following document to the query on a scale of 0.0 to 10.0.

Query: "${question}"

Document: "...${textPreview}..."

Scoring Criteria:
- 10: Contains the exact answer/fact requested.
- 5-9: Discusses the topic closely but might miss specific details.
- 0-4: Tangentially related or irrelevant.

Output: Return ONLY the number (e.g., 8.5). No explanation.`;

  try {
    const response = await httpRequest({
      method: 'POST',
      url: `${OLLAMA_URL}/api/chat`,
      body: {
        model: MODEL_NAME,
        messages: [{ role: 'user', content: prompt }],
        stream: false,
        options: { temperature: 0, num_predict: 10 }
      },
      json: true
    });

    // Parse the numeric score from response
    const content = response?.message?.content || '0';
    const match = content.match(/[\d]+(\.[\ d]+)?/);
    const score = match ? parseFloat(match[0]) : 0;

    return {
      ...doc,
      reranker_score: score,
      // Weighted: 90% AI score, 10% keyword score
      final_score: (score * 0.9) + ((doc.keyword_score || 0) * 0.1)
    };

  } catch (error) {
    // Fallback on error - use keyword score only
    return {
      ...doc,
      reranker_score: 0,
      final_score: (doc.keyword_score || 0),
      error: error.message
    };
  }
});

// Wait for all scoring to complete
const results = await Promise.all(scorePromises);

// Sort by final score and take top K
const topResults = results
  .sort((a, b) => b.final_score - a.final_score)
  .slice(0, TOP_K);

return [{ json: {
  config,
  question,
  family_id,
  chat_history: chat_history || [],
  top_results: topResults
}}];

const inputData = $input.first().json;
const config = inputData.config;
const question = inputData.question;
const results = inputData.top_results;
const chatHistory = inputData.chat_history || [];

// Build context with clean source format
const contextBlocks = results.map((r, i) => {
  const docTitle = r.title || 'Unknown Document';
  const pageNum = r.page_num || 1;
  const contextText = r.context_text || r.text || '';

  return `--- Source: ${docTitle}, Page ${pageNum} ---\n${contextText}`;
}).join('\n\n');

const systemPrompt = `You are Mattervault, an expert legal analyst and estate planning assistant.

CRITICAL RULES:
1. Answer ONLY based on the provided Context documents below
2. If the answer is not in the context, say "I don't have information about that in the provided documents"
3. NEVER make up legal facts or information
4. For EVERY fact you state, cite the source using this EXACT format: (Source: [Document Title], Page [N])
5. Be concise but thorough
6. Do NOT use numbered source references like "Source 1" - always use the full document name
7. You may reference previous conversation for context, but all facts MUST come from the documents`;

// Build messages array with chat history
const messages = [
  { role: 'system', content: systemPrompt }
];

// Add chat history (previous Q&A pairs)
for (const msg of chatHistory) {
  messages.push({
    role: msg.role === 'assistant' ? 'assistant' : 'user',
    content: msg.content
  });
}

// Add current user question with document context
const userPrompt = `Context Documents:\n${contextBlocks}\n\n---\n\nQuestion: ${question}\n\nAnswer based ONLY on the context documents above. Cite each fact with (Source: [Document Title], Page [N]).`;
messages.push({ role: 'user', content: userPrompt });

return [{
  json: {
    config: config,
    messages: messages,
    sources: results.map(r => ({
      title: r.title || 'Unknown',
      page: r.page_num || 1,
      document_id: r.payload?.document_id || null
    }))
  }
}];

const response = $input.first().json;
const promptData = $('Build LLM Prompt').first().json;
const sources = promptData.sources;

let answer = '';
if (response.message && response.message.content) {
  answer = response.message.content;
} else if (response.response) {
  answer = response.response;
} else {
  answer = 'I encountered an issue generating a response. Please try again.';
}

// Deduplicate sources by title+page
const seen = new Set();
const uniqueSources = sources.filter(s => {
  const key = `${s.title}-${s.page}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

const sourcesList = uniqueSources.map(s => `- ${s.title}, Page ${s.page}`).join('\n');

// Build citations array with document IDs for UI
const citations = uniqueSources.map(s => ({
  source: s.title,
  page: s.page,
  document_id: s.document_id
}));

return [{ json: {
  output: answer + '\n\n---\n**Sources consulted:**\n' + sourcesList,
  citations: citations
}}];
